import{_ as t,o as a,c as s,a0 as i}from"./chunks/framework.CWk8AOcY.js";const u=JSON.parse('{"title":"Multi-Node Cluster Deployment","description":"","frontmatter":{},"headers":[],"relativePath":"guide/multi-node-deploy.md","filePath":"guide/multi-node-deploy.md"}'),o={name:"guide/multi-node-deploy.md"};function n(l,e,d,r,p,h){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="multi-node-cluster-deployment" tabindex="-1">Multi-Node Cluster Deployment <a class="header-anchor" href="#multi-node-cluster-deployment" aria-label="Permalink to &quot;Multi-Node Cluster Deployment&quot;">​</a></h1><p>This guide explains how to expand a single-node Cube Sandbox deployment into a multi-node cluster by adding <strong>compute nodes</strong>. Compute nodes run only the sandbox runtime components (<code>Cubelet</code>, <code>network-agent</code>, <code>CubeShim</code>) and register themselves to the control plane on the first machine.</p><div class="tip custom-block"><p class="custom-block-title">Prerequisite</p><p>You must have a working control node deployed via the <a href="./self-build-deploy.html">Self-Build Deployment Guide</a> before adding compute nodes.</p></div><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────┐</span></span>
<span class="line"><span>│           Control Node                  │</span></span>
<span class="line"><span>│  CubeMaster, cube-api, CubeProxy,      │</span></span>
<span class="line"><span>│  CoreDNS, MySQL, Redis,                │</span></span>
<span class="line"><span>│  Cubelet, network-agent                 │</span></span>
<span class="line"><span>└──────────────────┬──────────────────────┘</span></span>
<span class="line"><span>                   │  /internal/meta API</span></span>
<span class="line"><span>       ┌───────────┼───────────┐</span></span>
<span class="line"><span>       ▼           ▼           ▼</span></span>
<span class="line"><span>┌────────────┐┌────────────┐┌────────────┐</span></span>
<span class="line"><span>│ Compute #1 ││ Compute #2 ││ Compute #N │</span></span>
<span class="line"><span>│ Cubelet    ││ Cubelet    ││ Cubelet    │</span></span>
<span class="line"><span>│ net-agent  ││ net-agent  ││ net-agent  │</span></span>
<span class="line"><span>└────────────┘└────────────┘└────────────┘</span></span></code></pre></div><ul><li>The <strong>control node</strong> runs the full stack: orchestration (CubeMaster), API gateway (cube-api), proxy (CubeProxy + CoreDNS), databases (MySQL + Redis), and also acts as a compute node itself.</li><li>Each <strong>compute node</strong> runs only <code>Cubelet</code> and <code>network-agent</code>. It registers to the control-plane <code>CubeMaster</code> and receives sandbox scheduling requests.</li></ul><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Each compute node must meet the same hardware and software requirements as the control node:</p><ul><li><strong>Physical machine or bare-metal server</strong> (nested virtualization is not supported)</li><li><strong>x86_64</strong> architecture with <strong>KVM enabled</strong> (<code>ls /dev/kvm</code>)</li><li><strong>Docker</strong> installed and running</li><li><strong>Network connectivity</strong> to the control node (specifically to <code>CubeMaster</code> on port <code>8089</code> by default)</li></ul><p>For the full requirements list, see <a href="./self-build-deploy.html#prerequisites">Self-Build Deployment — Prerequisites</a>.</p><h2 id="step-1-prepare-the-release-bundle" tabindex="-1">Step 1: Prepare the Release Bundle <a class="header-anchor" href="#step-1-prepare-the-release-bundle" aria-label="Permalink to &quot;Step 1: Prepare the Release Bundle&quot;">​</a></h2><p>Use the <strong>same release bundle</strong> that was built for the control node. Copy it to the compute node and extract:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tar</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -xzf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cube-sandbox-one-click-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">versio</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.tar.gz</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cube-sandbox-one-click-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">versio</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><h2 id="step-2-configure-environment-variables" tabindex="-1">Step 2: Configure Environment Variables <a class="header-anchor" href="#step-2-configure-environment-variables" aria-label="Permalink to &quot;Step 2: Configure Environment Variables&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> env.example</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env</span></span></code></pre></div><p>Edit <code>.env</code> and set the following variables:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ONE_CLICK_DEPLOY_ROLE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">compute</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CUBE_SANDBOX_NODE_IP</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">current-node-ip</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ONE_CLICK_CONTROL_PLANE_IP</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">control-plane-ip</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>ONE_CLICK_DEPLOY_ROLE</code></td><td>Must be set to <code>compute</code> for compute-only nodes</td></tr><tr><td><code>CUBE_SANDBOX_NODE_IP</code></td><td>This node&#39;s primary network interface IP</td></tr><tr><td><code>ONE_CLICK_CONTROL_PLANE_IP</code></td><td>The control node&#39;s IP; automatically expanded to <code>&lt;ip&gt;:8089</code> for CubeMaster</td></tr></tbody></table><p>You can also specify the CubeMaster endpoint explicitly if it uses a non-default port:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ONE_CLICK_CONTROL_PLANE_CUBEMASTER_ADDR</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">control-plane-ip</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:8089</span></span></code></pre></div><p><code>ONE_CLICK_CONTROL_PLANE_CUBEMASTER_ADDR</code> takes precedence over <code>ONE_CLICK_CONTROL_PLANE_IP</code> when both are set.</p><h2 id="step-3-install" tabindex="-1">Step 3: Install <a class="header-anchor" href="#step-3-install" aria-label="Permalink to &quot;Step 3: Install&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./install-compute.sh</span></span></code></pre></div><p>The compute-node install script will:</p><ol><li>Install only <code>Cubelet</code>, <code>network-agent</code>, <code>cube-shim</code>, <code>cube-image</code>, <code>cube-kernel-scf</code>, and the runtime scripts</li><li>Start only the host processes <code>network-agent</code> and <code>cubelet</code></li><li>Automatically point <code>Cubelet</code>&#39;s <code>meta_server_endpoint</code> to the control-plane <code>CubeMaster</code></li><li>Register the node and report status through the control plane <code>/internal/meta</code> API</li></ol><h2 id="verifying-the-deployment" tabindex="-1">Verifying the Deployment <a class="header-anchor" href="#verifying-the-deployment" aria-label="Permalink to &quot;Verifying the Deployment&quot;">​</a></h2><h3 id="health-check" tabindex="-1">Health Check <a class="header-anchor" href="#health-check" aria-label="Permalink to &quot;Health Check&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./smoke.sh</span></span></code></pre></div><p>In compute-node mode, <code>quickcheck.sh</code> verifies:</p><ul><li>Local <code>network-agent</code> health</li><li>Reachability of the control-plane <code>CubeMaster</code></li><li>That the current node appears under <code>/internal/meta/nodes/{node_id}</code> on the control plane</li></ul><h3 id="verify-from-the-control-node" tabindex="-1">Verify from the Control Node <a class="header-anchor" href="#verify-from-the-control-node" aria-label="Permalink to &quot;Verify from the Control Node&quot;">​</a></h3><p>On the control node, you can confirm the compute node has registered:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8089/internal/meta/nodes</span></span></code></pre></div><p>The response should include the compute node&#39;s IP and a healthy status.</p><h2 id="common-operations" tabindex="-1">Common Operations <a class="header-anchor" href="#common-operations" aria-label="Permalink to &quot;Common Operations&quot;">​</a></h2><h3 id="stop-compute-node-services" tabindex="-1">Stop Compute Node Services <a class="header-anchor" href="#stop-compute-node-services" aria-label="Permalink to &quot;Stop Compute Node Services&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./down.sh</span></span></code></pre></div><p>In compute-node mode, this only stops <code>cubelet</code> and <code>network-agent</code>. It does not affect the control plane or other compute nodes.</p><h3 id="reinstall" tabindex="-1">Reinstall <a class="header-anchor" href="#reinstall" aria-label="Permalink to &quot;Reinstall&quot;">​</a></h3><p>To reinstall a compute node, simply run <code>install-compute.sh</code> again. The script automatically stops the existing deployment before installing.</p><h3 id="view-logs" tabindex="-1">View Logs <a class="header-anchor" href="#view-logs" aria-label="Permalink to &quot;View Logs&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Component</th><th>Log Path</th></tr></thead><tbody><tr><td>Cubelet</td><td><code>/data/log/Cubelet/</code></td></tr><tr><td>CubeShim</td><td><code>/data/log/CubeShim/</code></td></tr><tr><td>Hypervisor (VMM)</td><td><code>/data/log/CubeVmm/</code></td></tr><tr><td>Runtime PID files</td><td><code>/var/run/cube-sandbox-one-click/</code></td></tr><tr><td>Process stdout/stderr</td><td><code>/var/log/cube-sandbox-one-click/</code></td></tr></tbody></table><p>For control-node log paths, see <a href="./self-build-deploy.html#view-logs">Self-Build Deployment — View Logs</a>.</p><h2 id="configuration-reference" tabindex="-1">Configuration Reference <a class="header-anchor" href="#configuration-reference" aria-label="Permalink to &quot;Configuration Reference&quot;">​</a></h2><p>Compute nodes use the same <code>.env</code> file format. The following variables are specific to or particularly relevant for compute-node deployments:</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>ONE_CLICK_DEPLOY_ROLE</code></td><td><code>control</code></td><td>Must be set to <code>compute</code></td></tr><tr><td><code>ONE_CLICK_CONTROL_PLANE_IP</code></td><td>empty</td><td>Control-plane host IP; expanded to <code>&lt;ip&gt;:8089</code> by default</td></tr><tr><td><code>ONE_CLICK_CONTROL_PLANE_CUBEMASTER_ADDR</code></td><td>empty</td><td>Explicit CubeMaster address; takes precedence over <code>ONE_CLICK_CONTROL_PLANE_IP</code></td></tr><tr><td><code>CUBE_SANDBOX_NODE_IP</code></td><td><code>10.0.0.10</code></td><td><strong>Required.</strong> This node&#39;s primary network interface IP</td></tr><tr><td><code>ONE_CLICK_INSTALL_PREFIX</code></td><td><code>/usr/local/services/cubetoolbox</code></td><td>Installation directory</td></tr><tr><td><code>ONE_CLICK_RUN_QUICKCHECK</code></td><td><code>1</code></td><td>Run health check after installation</td></tr></tbody></table><p>For the full configuration reference (build-time options, database, proxy, etc.), see <a href="./self-build-deploy.html#configuration-reference">Self-Build Deployment — Configuration Reference</a>.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="compute-node-cannot-reach-cubemaster" tabindex="-1">Compute Node Cannot Reach CubeMaster <a class="header-anchor" href="#compute-node-cannot-reach-cubemaster" aria-label="Permalink to &quot;Compute Node Cannot Reach CubeMaster&quot;">​</a></h3><p>Verify network connectivity:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">control-plane-i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:8089/internal/meta/nodes</span></span></code></pre></div><p>If this fails, check:</p><ul><li>Firewall rules on the control node (port <code>8089</code> must be accessible)</li><li>The <code>ONE_CLICK_CONTROL_PLANE_IP</code> or <code>ONE_CLICK_CONTROL_PLANE_CUBEMASTER_ADDR</code> value in <code>.env</code></li></ul><h3 id="node-not-appearing-in-control-plane" tabindex="-1">Node Not Appearing in Control Plane <a class="header-anchor" href="#node-not-appearing-in-control-plane" aria-label="Permalink to &quot;Node Not Appearing in Control Plane&quot;">​</a></h3><p>If <code>smoke.sh</code> passes locally but the node does not appear on the control plane:</p><ol><li>Check Cubelet logs: <code>/data/log/Cubelet/</code></li><li>Verify <code>meta_server_endpoint</code> in the Cubelet config points to the correct CubeMaster address</li><li>Ensure <code>CUBE_SANDBOX_NODE_IP</code> is correctly set to a routable IP (not <code>127.0.0.1</code>)</li></ol><p>For general troubleshooting (Docker, KVM, DNS, etc.), see <a href="./self-build-deploy.html#troubleshooting">Self-Build Deployment — Troubleshooting</a>.</p>`,57)])])}const k=t(o,[["render",n]]);export{u as __pageData,k as default};
